SUPPORTED_FORMATS = ['tar.gz', 'tar.bz2', 'zip', '7z']


def get_timestamp():
    """Generate a timestamp string for the backup filename."""
    return datetime.datetime.now().strftime('%Y%m%d_%H%M%S')


def get_dir_size(path):
    """Calculate total size of a directory in bytes."""
    total_size = 0
    for dirpath, dirnames, filenames in os.walk(path):
        for f in filenames:
            fp = os.path.join(dirpath, f)
            try:
                total_size += os.path.getsize(fp)
            except OSError:
                pass
    return total_size


def format_size(size_bytes):
    """Format bytes into human-readable string."""
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size_bytes < 1024.0:
            return "%.2f %s" % (size_bytes, unit)
        size_bytes /= 1024.0
    return "%.2f PB" % size_bytes


def validate_directory(directory):
    """Validate that the given path is an existing, readable directory."""
    if not os.path.exists(directory):
        raise ValueError("Directory does not exist: %s" % directory)
    if not os.path.isdir(directory):
        raise ValueError("Path is not a directory: %s" % directory)
    if not os.access(directory, os.R_OK):
        raise ValueError("Directory is not readable: %s" % directory)
    return os.path.abspath(directory)


def validate_output_dir(output_dir):
    """Validate or create the output directory."""
    if not os.path.exists(output_dir):
        try:
            os.makedirs(output_dir)
            print("Created output directory: %s" % output_dir)
        except OSError as e:
            if e.errno != errno.EEXIST:
                raise ValueError("Cannot create output directory: %s - %s" % (output_dir, str(e)))
    if not os.access(output_dir, os.W_OK):
        raise ValueError("Output directory is not writable: %s" % output_dir)
    return os.path.abspath(output_dir)


