def create_tar_gz(source_dir, output_path, verbose=False):
    """Create a tar.gz compressed archive."""
    archive_name = output_path + '.tar.gz'
    print("Creating tar.gz archive: %s" % archive_name)

    failed_files = []

    try:
        with tarfile.open(archive_name, 'w:gz') as tar:
            base_name = os.path.basename(source_dir)
            for root, dirs, files in os.walk(source_dir):
                for file_name in files:
                    file_path = os.path.join(root, file_name)
                    arcname = os.path.join(
                        base_name,
                        os.path.relpath(file_path, source_dir)
                    )
                    try:
                        tar.add(file_path, arcname=arcname)
                        if verbose:
                            print("  Added: %s" % arcname)
                    except (OSError, IOError, tarfile.TarError) as e:
                        failed_files.append((file_path, str(e)))
                        print("  WARNING: Could not add %s: %s" % (file_path, str(e)))

                # Also add empty directories
                for dir_name in dirs:
                    dir_path = os.path.join(root, dir_name)
                    arcname = os.path.join(
                        base_name,
                        os.path.relpath(dir_path, source_dir)
                    )
                    try:
                        tar.add(dir_path, arcname=arcname, recursive=False)
                    except (OSError, IOError, tarfile.TarError):
                        pass

    except tarfile.TarError as e:
        raise RuntimeError("Failed to create tar.gz archive: %s" % str(e))

    return archive_name, failed_files


