def create_zip(source_dir, output_path, verbose=False):
    """Create a zip compressed archive."""
    archive_name = output_path + '.zip'
    print("Creating zip archive: %s" % archive_name)

    failed_files = []

    try:
        # Use ZIP_DEFLATED if available, fall back to ZIP_STORED
        try:
            import zlib  # noqa: F401
            compression = zipfile.ZIP_DEFLATED
        except ImportError:
            compression = zipfile.ZIP_STORED
            print("  WARNING: zlib not available, using ZIP_STORED (no compression)")

        with zipfile.ZipFile(archive_name, 'w', compression) as zf:
            base_name = os.path.basename(source_dir)
            for root, dirs, files in os.walk(source_dir):
                # Add directory entries
                for dir_name in dirs:
                    dir_path = os.path.join(root, dir_name)
                    arcname = os.path.join(
                        base_name,
                        os.path.relpath(dir_path, source_dir)
                    ) + '/'
                    try:
                        zf.write(dir_path, arcname)
                    except (OSError, IOError):
                        pass

                for file_name in files:
                    file_path = os.path.join(root, file_name)
                    arcname = os.path.join(
                        base_name,
                        os.path.relpath(file_path, source_dir)
                    )
                    try:
                        zf.write(file_path, arcname)
                        if verbose:
                            print("  Added: %s" % arcname)
                    except (OSError, IOError) as e:
                        failed_files.append((file_path, str(e)))
                        print("  WARNING: Could not add %s: %s" % (file_path, str(e)))

    except zipfile.BadZipFile as e:
        raise RuntimeError("Failed to create zip archive: %s" % str(e))
    except Exception as e:
        raise RuntimeError("Failed to create zip archive: %s" % str(e))

    return archive_name, failed_files


def create_7z(source_dir, output_path, verbose=False):
    """Create a 7z compressed archive using the 7z command-line tool."""
    archive_name = output_path + '.7z'
    print("Creating 7z archive: %s" % archive_name)

    # Determine which 7z binary is available
