    for cmd in ['7z', '7za', '7zr']:
        try:
            devnull = open(os.devnull, 'w')
            subprocess.call([cmd], stdout=devnull, stderr=devnull)
            devnull.close()
            seven_z_cmd = cmd
            break
        except (OSError, subprocess.CalledProcessError):
            continue

    if seven_z_cmd is None:
        raise RuntimeError(
            "7z command-line tool not found. "
            "Please install p7zip or p7zip-full package.\n"
            "  Debian/Ubuntu: sudo apt-get install p7zip-full\n"
            "  CentOS/RHEL:   sudo yum install p7zip p7zip-plugins\n"
            "  macOS:         brew install p7zip"
        )

    cmd = [seven_z_cmd, 'a', '-t7z', '-mx=5']
    if not verbose:
        cmd.append('-bd')  # Disable progress indicator

    cmd.append(archive_name)
    cmd.append(source_dir)

    try:
        if verbose:
            result = subprocess.call(cmd)
        else:
            devnull = open(os.devnull, 'w')
            result = subprocess.call(cmd, stdout=devnull, stderr=devnull)
            devnull.close()

        if result != 0:
            raise RuntimeError("7z command exited with code %d" % result)

    except OSError as e:
        raise RuntimeError("Failed to run 7z command: %s" % str(e))

    # 7z handles its own error reporting, so we return empty failed list
    return archive_name, []


