def create_backup(source_dir, fmt, output_dir=None, verbose=False):
    """
    Create a backup archive of the given directory.

    Args:
        source_dir: Path to the directory to back up
        fmt: Compression format (tar.gz, tar.bz2, zip, 7z)
        output_dir: Directory to store the backup (default: current directory)
        verbose: Print detailed progress

    Returns:
        Tuple of (archive_path, list_of_failed_files)
    """
    # Validate inputs
    source_dir = validate_directory(source_dir)

    if fmt not in SUPPORTED_FORMATS:
        raise ValueError(
            "Unsupported format: %s. Supported formats: %s"
            % (fmt, ', '.join(SUPPORTED_FORMATS))
        )

    if output_dir is None:
        output_dir = os.getcwd()
    output_dir = validate_output_dir(output_dir)

    # Generate output filename
    dir_name = os.path.basename(source_dir.rstrip(os.sep))
    if not dir_name:
        dir_name = 'root'
    timestamp = get_timestamp()
    output_base = os.path.join(output_dir, "backup_%s_%s" % (dir_name, timestamp))

    # Calculate source size
