    print("Source directory: %s" % source_dir)
    print("Source size: %s" % format_size(source_size))
    print("Format: %s" % fmt)
    print("")

    # Create the archive
    handler = FORMAT_HANDLERS[fmt]
    archive_path, failed_files = handler(source_dir, output_base, verbose)

    # Report results
    if os.path.exists(archive_path):
        archive_size = os.path.getsize(archive_path)
        print("")
        print("Backup completed successfully!")
        print("Archive: %s" % archive_path)
        print("Archive size: %s" % format_size(archive_size))
        if source_size > 0:
            ratio = (1.0 - float(archive_size) / float(source_size)) * 100
            print("Compression ratio: %.1f%% reduction" % ratio)
    else:
        print("ERROR: Archive file was not created!")

    if failed_files:
        print("")
        print("WARNING: %d file(s) could not be added:" % len(failed_files))
        for fpath, reason in failed_files:
            print("  %s: %s" % (fpath, reason))

    return archive_path, failed_files


